import React from "react"

type Props = {
  title: string,
  url: string,
}

const Share: React.FC<Props> = ({title, url}) => {
  const tweet = `https://twitter.com/intent/tweet?text=` + encodeURIComponent(`${title} ${url}`)
  return (
      <a href={tweet}>
          <span className="icon-twitter">
          tweet
          </span>
      </a>
  )
}

export default Share
